script:
// Service Report Work Times Calendar v10.1
// Merged: prod v9 button CSS (via JS injection for shadow DOM compat) + local v8 bugfixes
(function() {
    var calendar = null;
    var currentEmployee = null;
    var calendarEl = null;
    var showWeekends = true;
    var currentMinTime = '06:00:00';
    var currentMaxTime = '22:00:00';

    var container = root_element.querySelector('.sr-calendar-container');
    if (!container) return;

    var calendarPlaceholder = root_element.querySelector('#work-times-calendar');
    var startDateInput = root_element.querySelector('#filter-start-date');
    var endDateInput = root_element.querySelector('#filter-end-date');
    var weekendToggleBtn = root_element.querySelector('#btn-toggle-weekends');

    function formatLocalDate(d) {
        return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
    }

    function getCustomerColor(customerName) {
        if (!customerName || customerName === '') return 'hsl(200, 70%, 45%)';
        var hash = 0;
        for (var i = 0; i < customerName.length; i++) {
            hash = customerName.charCodeAt(i) + ((hash << 5) - hash);
        }
        var hue = Math.abs(hash % 360);
        return 'hsl(' + hue + ', 65%, 45%)';
    }

    async function init() {
        await loadDependencies();
        createCalendarElement();
        await getCurrentEmployee();
        setInitialFilters();
        initCalendar();
        setupEventListeners();
    }

    async function loadDependencies() {
        if (!frappe.FullCalendar) {
            await frappe.require('calendar.bundle.js');
        }
    }

    function createCalendarElement() {
        calendarEl = document.createElement('div');
        calendarPlaceholder.appendChild(calendarEl);

        // Inject FullCalendar styles into document.head (not shadow DOM)
        // because FullCalendar renders outside the Custom HTML Block's shadow root
        var styleId = 'sr-calendar-fc-styles';
        if (!document.getElementById(styleId)) {
            var style = document.createElement('style');
            style.id = styleId;
            style.textContent =
                '#work-times-calendar .fc .fc-button { display: inline-flex !important; align-items: center !important; justify-content: center !important; padding: 4px 12px !important; line-height: 1.2 !important; min-width: 36px; vertical-align: middle; }' +
                '#work-times-calendar .fc .fc-button .fc-icon { font-size: 1.1em; }' +
                '#work-times-calendar .fc .fc-toolbar { flex-wrap: wrap; }' +
                '#work-times-calendar .fc .fc-toolbar-title { font-size: 1.1rem; }' +
                '#work-times-calendar .fc-bg-event.core-hours { background-color: rgba(0, 0, 0, 0.08) !important; opacity: 1 !important; }' +
                '#work-times-calendar .fc-non-business { background-color: transparent !important; }' +
                '#work-times-calendar .fc-timegrid-slot { height: 10px !important; }' +
                '#work-times-calendar .fc-timegrid-slot-minor { height: 10px !important; }' +
                '#work-times-calendar .fc-timegrid-axis { font-size: 11px !important; padding: 0 4px !important; }' +
                '#work-times-calendar .fc-event { cursor: pointer; border: none; border-radius: 3px; padding: 2px 4px; font-size: 11px; }';
            document.head.appendChild(style);
        }
    }

    async function getCurrentEmployee() {
        try {
            var response = await frappe.call({
                method: 'fieldservice.api.get_current_employee',
                async: true
            });
            currentEmployee = response.message;
        } catch (error) {
            console.error('Fehler:', error);
        }
    }

    function toggleWeekends() {
        showWeekends = !showWeekends;
        if (calendar) {
            calendar.setOption('weekends', showWeekends);
        }
        updateWeekendButtonText();
    }

    function updateWeekendButtonText() {
        if (weekendToggleBtn) {
            weekendToggleBtn.textContent = showWeekends ? 'Nur Werktage' : 'Ganze Woche';
        }
    }

    function calculateTimeRange(events) {
        if (!events || events.length === 0) {
            return { minTime: '06:00:00', maxTime: '22:00:00' };
        }

        var minHour = 24;
        var maxHour = 0;

        events.forEach(function(event) {
            var startDate = new Date(event.start);
            var endDate = new Date(event.end);

            var startHour = startDate.getHours();
            var endHour = endDate.getHours();
            var endMinute = endDate.getMinutes();

            if (endMinute > 0) {
                endHour = endHour + 1;
            }

            if (startHour < minHour) minHour = startHour;
            if (endHour > maxHour) maxHour = endHour;
        });

        minHour = Math.max(0, minHour - 1);
        maxHour = Math.min(24, maxHour + 1);
        minHour = Math.min(minHour, 6);
        maxHour = Math.max(maxHour, 22);

        return {
            minTime: (minHour < 10 ? '0' : '') + minHour + ':00:00',
            maxTime: (maxHour < 10 ? '0' : '') + maxHour + ':00:00'
        };
    }

    function updateCalendarTimeRange(minTime, maxTime) {
        if (!calendar) return;

        if (minTime !== currentMinTime || maxTime !== currentMaxTime) {
            currentMinTime = minTime;
            currentMaxTime = maxTime;
            calendar.setOption('slotMinTime', minTime);
            calendar.setOption('slotMaxTime', maxTime);
        }
    }

    function generateCoreHoursEvents(fetchInfo) {
        var bgEvents = [];
        var current = new Date(fetchInfo.start);
        var end = new Date(fetchInfo.end);
        while (current < end) {
            var dayOfWeek = current.getDay();
            if (dayOfWeek >= 1 && dayOfWeek <= 5) {
                var dateStr = formatLocalDate(current);
                bgEvents.push({
                    start: dateStr + 'T08:00:00',
                    end: dateStr + 'T17:00:00',
                    display: 'background',
                    classNames: ['core-hours']
                });
            }
            current.setDate(current.getDate() + 1);
        }
        return bgEvents;
    }

    function initCalendar() {
        calendar = new frappe.FullCalendar(calendarEl, {
            plugins: frappe.FullCalendar.Plugins,
            locale: frappe.boot.lang || 'de',
            headerToolbar: { left: 'prev,next today', center: 'title', right: 'dayGridMonth,timeGridWeek,timeGridDay' },
            initialView: 'timeGridWeek',
            firstDay: 1,
            weekends: showWeekends,
            editable: false,
            selectable: false,
            nowIndicator: true,
            slotDuration: '00:30:00',
            slotMinTime: currentMinTime,
            slotMaxTime: currentMaxTime,
            height: 'auto',
            slotLabelFormat: { hour: '2-digit', minute: '2-digit', hour12: false },
            eventTimeFormat: { hour: '2-digit', minute: '2-digit', hour12: false },
            buttonText: { today: 'Heute', month: 'Monat', week: 'Woche', day: 'Tag' },
            eventSources: [
                { events: function(fetchInfo, successCallback, failureCallback) { fetchEvents(fetchInfo, successCallback, failureCallback); } },
                { events: function(fetchInfo, successCallback) { successCallback(generateCoreHoursEvents(fetchInfo)); } }
            ],
            eventClick: function(info) {
                var serviceReport = info.event.extendedProps ? info.event.extendedProps.service_report : null;
                if (serviceReport) {
                    frappe.set_route('Form', 'Service Report', serviceReport);
                }
            },
            eventDidMount: function(info) {
                if (info.event.display === 'background') return;
                var color = getCustomerColor(info.event.extendedProps.customer_name || '');
                info.el.style.backgroundColor = color;
                info.el.style.borderColor = color;
                info.el.style.cursor = 'pointer';
                info.el.title = (info.event.title || '') + ' - Klicken zum \u00d6ffnen';
            }
        });
        calendar.render();
    }

    function fetchEvents(fetchInfo, successCallback, failureCallback) {
        if (!currentEmployee) { successCallback([]); return; }
        var startStr = formatLocalDate(fetchInfo.start);
        var endStr = formatLocalDate(fetchInfo.end);
        frappe.call({
            method: 'fieldservice.api.get_service_report_work_times',
            args: {
                start: startStr,
                end: endStr,
                employees: JSON.stringify([currentEmployee.name])
            },
            async: true,
            callback: function(response) {
                var events = response.message || [];
                var timeRange = calculateTimeRange(events);
                updateCalendarTimeRange(timeRange.minTime, timeRange.maxTime);
                successCallback(events);
            },
            error: function() { successCallback([]); }
        });
    }

    function setupEventListeners() {
        if (weekendToggleBtn) {
            weekendToggleBtn.addEventListener('click', toggleWeekends);
        }
        if (startDateInput) {
            startDateInput.addEventListener('change', function() {
                if (startDateInput.value && calendar) {
                    calendar.gotoDate(startDateInput.value);
                }
            });
        }
    }

    function setInitialFilters() {
        var today = new Date();
        var monday = new Date(today);
        var diff = today.getDay() === 0 ? -6 : 1 - today.getDay();
        monday.setDate(today.getDate() + diff);
        var sunday = new Date(monday);
        sunday.setDate(monday.getDate() + 6);
        if (startDateInput) startDateInput.value = formatLocalDate(monday);
        if (endDateInput) endDateInput.value = formatLocalDate(sunday);
    }

    init();
})();

style:
.sr-calendar-container {
    padding: 15px;
    background: var(--card-bg);
    border-radius: var(--border-radius);
}

.calendar-filters {
    background: var(--subtle-fg);
    padding: 10px 15px;
    border-radius: var(--border-radius);
    margin-bottom: 15px;
}

.filter-row {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    align-items: center;
}

.filter-row > label {
    font-weight: 600;
    font-size: 12px;
    color: var(--text-muted);
    margin: 0;
}

.filter-row > span {
    color: var(--text-muted);
}

.filter-row > input {
    width: 140px;
    background-color: var(--card-bg) !important;
    border: 1px solid var(--border-color) !important;
}

.filter-row > .btn {
    background-color: var(--card-bg) !important;
    border: 1px solid var(--border-color) !important;
    margin-left: auto;
}

/* Event popup modal */

.event-popup {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0,0,0,0.5);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 1060;
}

.event-popup.hidden {
    display: none;
}

.event-popup-content {
    background: var(--card-bg);
    border-radius: var(--border-radius-lg);
    max-width: 500px;
    width: 90%;
    max-height: 80vh;
    overflow-y: auto;
    box-shadow: var(--shadow-lg);
}

.event-popup-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px;
    border-bottom: 1px solid var(--border-color);
}

.event-popup-header h4 {
    margin: 0;
    font-size: 14px;
    font-weight: 600;
}

.popup-close-btn {
    background: none;
    border: none;
    font-size: 22px;
    cursor: pointer;
    color: var(--text-muted);
    line-height: 1;
    padding: 0;
}

.event-popup-body {
    padding: 15px;
}

.popup-field {
    margin-bottom: 12px;
}

.popup-field label {
    display: block;
    font-size: 11px;
    color: var(--text-muted);
    margin-bottom: 2px;
}

.popup-field span {
    font-size: 13px;
}

.popup-description {
    background: var(--subtle-fg);
    padding: 10px;
    border-radius: var(--border-radius);
    max-height: 120px;
    overflow-y: auto;
    font-size: 12px;
}

.popup-actions {
    margin-top: 15px;
    padding-top: 15px;
    border-top: 1px solid var(--border-color);
}

.service-type-badge {
    display: inline-block;
    padding: 2px 8px;
    border-radius: 10px;
    font-size: 11px;
    font-weight: 500;
    background: var(--subtle-fg);
}
